# Raycast AI extension — example custom commands

Name:    Draft Reply
Prompt:  You are a professional assistant. Draft a concise, polite reply
         to the following message: {selection}

Name:    Summarize
Prompt:  Summarize the following text in three bullet points: {selection}

Name:    Convert to Markdown Table
Prompt:  Convert the following tabular data to a Markdown table: {selection}

{
  "mcpServers": {
    "filesystem": {
      "command": "npx",
      "args": ["-y", "@modelcontextprotocol/server-filesystem", "/Users/me/projects"],
      "env": {}
    },
    "github": {
      "command": "npx",
      "args": ["-y", "@modelcontextprotocol/server-github"],
      "env": { "GITHUB_PERSONAL_ACCESS_TOKEN": "ghp_..." }
    }
  }
}
